import express, { Request, Response } from "express";
import { Client } from "pg";

const app = express();
app.use(express.json());

const client = new Client({
  connectionString: process.env.DATABASE_URL || "postgres://localhost:5432/mydb"
});

client.connect().catch((err) => console.error("Connection error:", err));

app.get("/api/search", async (req: Request, res: Response) => {
  try {
    // Build conditions dynamically from query parameters
    let conditions = "1=1";
    if (Object.keys(req.query).length > 0) {
      const filters = Object.entries(req.query).map(([key, value]) => {
        // Wrap value in single quotes.
        return `${key} = '${value}'`;
      });
      conditions = filters.join(" AND ");
    }

    const queryText = `SELECT * FROM users WHERE ${conditions}`;
    const result = await client.query(queryText);
    res.json(result.rows);
  } catch (error) {
    console.error("Error executing query:", error);
    res.status(500).send("Server Error");
  }
});

const PORT = process.env.PORT || 3000;
